async function callClaude(prompt) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method:"POST", headers:{"Content-Type":"application/json"},
    body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]}),
  });
  const data = await res.json();
  return data.content?.map(b=>b.text||"").join("\n")||"Error";
}

// ── 3D GALLERY ROOM ──
function GalleryRoom() {
  const mountRef = useRef(null);
  const sceneRef = useRef(null);

  useEffect(()=>{
    if(!mountRef.current) return;
    const el = mountRef.current;

    // Load Three.js dynamically
    const script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js';
    script.onload = () => {
      const THREE = window.THREE;
      const renderer = new THREE.WebGLRenderer({antialias:true});
      renderer.setPixelRatio(window.devicePixelRatio);
      renderer.shadowMap.enabled = true;
      renderer.setSize(el.clientWidth, el.clientHeight);
      el.appendChild(renderer.domElement);
      sceneRef.current = renderer;

      const scene = new THREE.Scene();
      scene.background = new THREE.Color(0xf0ece4);

      const camera = new THREE.PerspectiveCamera(45, el.clientWidth/el.clientHeight, 0.1, 100);
      camera.position.set(0, 1.8, 7);

      const TARGET = new THREE.Vector3(0,1.8,0);

      // Walls
      const wallMat = new THREE.MeshLambertMaterial({color:0xf5f0e8});
      const wallMatS = new THREE.MeshLambertMaterial({color:0xede8de});
      const backWall = new THREE.Mesh(new THREE.PlaneGeometry(18,9), wallMat);
      backWall.position.set(0,2.5,-8); scene.add(backWall);
      const lWall = new THREE.Mesh(new THREE.PlaneGeometry(16,9), wallMatS);
      lWall.rotation.y=Math.PI/2; lWall.position.set(-9,2.5,0); scene.add(lWall);
      const rWall = new THREE.Mesh(new THREE.PlaneGeometry(16,9), wallMatS);
      rWall.rotation.y=-Math.PI/2; rWall.position.set(9,2.5,0); scene.add(rWall);
      const ceil = new THREE.Mesh(new THREE.PlaneGeometry(18,16), new THREE.MeshLambertMaterial({color:0xfaf8f4}));
      ceil.rotation.x=Math.PI/2; ceil.position.set(0,7,0); scene.add(ceil);

      // Floor
      const floor = new THREE.Mesh(new THREE.PlaneGeometry(18,16), new THREE.MeshLambertMaterial({color:0xc8a870}));
      floor.rotation.x=-Math.PI/2; floor.position.set(0,-1.5,0); scene.add(floor);
      for(let i=-9;i<=9;i+=0.7){
        const plank=new THREE.Mesh(new THREE.PlaneGeometry(0.015,16),new THREE.MeshLambertMaterial({color:0xb89560}));
        plank.rotation.x=-Math.PI/2; plank.position.set(i,-1.49,0); scene.add(plank);
      }

      // Skirting
      const skirt=new THREE.Mesh(new THREE.BoxGeometry(18,0.2,0.06),new THREE.MeshLambertMaterial({color:0xe8e0d0}));
      skirt.position.set(0,-1.4,-7.97); scene.add(skirt);

      // Frame
      const paintW=7.0, paintH=2.9;
      const outerFrame=new THREE.Mesh(new THREE.BoxGeometry(paintW+0.4,paintH+0.4,0.12),new THREE.MeshLambertMaterial({color:0xb8922a}));
      outerFrame.position.set(0,2.4,-7.88); scene.add(outerFrame);
      const innerFrame=new THREE.Mesh(new THREE.BoxGeometry(paintW+0.15,paintH+0.15,0.13),new THREE.MeshLambertMaterial({color:0xd4aa50}));
      innerFrame.position.set(0,2.4,-7.87); scene.add(innerFrame);
      const mount=new THREE.Mesh(new THREE.BoxGeometry(paintW+0.05,paintH+0.05,0.14),new THREE.MeshLambertMaterial({color:0xf8f5ef}));
      mount.position.set(0,2.4,-7.86); scene.add(mount);

      // Painting texture — use canvas to load base64 image reliably
      const paintImg = new Image();
      paintImg.onload = () => {
        const tex = new THREE.Texture(paintImg);
        tex.minFilter = THREE.LinearFilter;
        tex.needsUpdate = true;
        const painting = new THREE.Mesh(
          new THREE.PlaneGeometry(paintW, paintH),
          new THREE.MeshBasicMaterial({map: tex, side: THREE.FrontSide})
        );
        painting.position.set(0, 2.4, -7.83);
        scene.add(painting);
      };
      paintImg.src = IMGS.full;

      // Lighting — bright
      scene.add(new THREE.AmbientLight(0xfff8f0, 2.2));
      const spot=new THREE.SpotLight(0xfffaee,4.0,25,Math.PI/5,0.5);
      spot.position.set(0,6.5,-3); spot.target.position.set(0,2.4,-7.88);
      scene.add(spot); scene.add(spot.target);
      const spot2=new THREE.SpotLight(0xfffaee,2.5,20,Math.PI/4,0.8);
      spot2.position.set(-2,6,-2); spot2.target.position.set(0,2.4,-7.88);
      scene.add(spot2); scene.add(spot2.target);
      scene.add(Object.assign(new THREE.PointLight(0xfff5e8,1.5,20),{position:{x:-5,y:5,z:0}}).position&&new THREE.PointLight(0xfff5e8,1.5,20));
      const fl1=new THREE.PointLight(0xfff5e8,1.5,20); fl1.position.set(-5,5,0); scene.add(fl1);
      const fl2=new THREE.PointLight(0xfff5e8,1.5,20); fl2.position.set(5,5,0); scene.add(fl2);
      const fl3=new THREE.PointLight(0xfff8f0,1.2,15); fl3.position.set(0,6,3); scene.add(fl3);

      // Bench
      const wood=new THREE.MeshLambertMaterial({color:0x7a5a30});
      const bench=new THREE.Mesh(new THREE.BoxGeometry(3.5,0.12,0.8),wood);
      bench.position.set(0,-0.6,3); scene.add(bench);
      [[-1.5,0.3],[1.5,0.3],[-1.5,-0.3],[1.5,-0.3]].forEach(([x,z])=>{
        const leg=new THREE.Mesh(new THREE.CylinderGeometry(0.05,0.05,0.9),wood);
        leg.position.set(x,-1.05,z+3); scene.add(leg);
      });

      // Orbit controls
      let isDrag=false,lastX=0,lastY=0,rotY=0,rotX=0.1,zoom=7;
      el.addEventListener('mousedown',e=>{isDrag=true;lastX=e.clientX;lastY=e.clientY;el.style.cursor='grabbing';});
      window.addEventListener('mouseup',()=>{isDrag=false;el.style.cursor='grab';});
      window.addEventListener('mousemove',e=>{
        if(!isDrag)return;
        rotY+=(e.clientX-lastX)*0.005; rotX+=(e.clientY-lastY)*0.003;
        rotX=Math.max(-0.2,Math.min(0.5,rotX)); lastX=e.clientX; lastY=e.clientY;
      });
      el.addEventListener('wheel',e=>{zoom=Math.max(3,Math.min(10,zoom+e.deltaY*0.01));});
      el.addEventListener('touchstart',e=>{isDrag=true;lastX=e.touches[0].clientX;lastY=e.touches[0].clientY;});
      el.addEventListener('touchend',()=>isDrag=false);
      el.addEventListener('touchmove',e=>{
        if(!isDrag)return;
        rotY+=(e.touches[0].clientX-lastX)*0.005; rotX+=(e.touches[0].clientY-lastY)*0.003;
        rotX=Math.max(-0.2,Math.min(0.5,rotX)); lastX=e.touches[0].clientX; lastY=e.touches[0].clientY;
      });

      let animId;
      const animate=()=>{
        animId=requestAnimationFrame(animate);
        if(!isDrag) rotY+=0.0008;
        camera.position.set(Math.sin(rotY)*zoom,TARGET.y+0.8-rotX*2,Math.cos(rotY)*zoom);
        camera.lookAt(TARGET);
        renderer.render(scene,camera);
      };
      animate();

      const onResize=()=>{
        renderer.setSize(el.clientWidth,el.clientHeight);
        camera.aspect=el.clientWidth/el.clientHeight;
        camera.updateProjectionMatrix();
      };
      window.addEventListener('resize',onResize);

      // Cleanup stored on ref
      sceneRef.current = { renderer, animId: {current:animId}, onResize };
    };
    document.head.appendChild(script);

    return ()=>{
      if(sceneRef.current){
        cancelAnimationFrame(sceneRef.current.animId?.current);
        window.removeEventListener('resize',sceneRef.current.onResize);
        sceneRef.current.renderer?.domElement?.remove();
      }
    };
  },[]);

  return(
    <div style={{position:"relative"}}>
      <div ref={mountRef} style={{width:"100%",height:"480px",cursor:"grab",background:"#f0ece4",borderRadius:"2px",overflow:"hidden"}}/>
      <div style={{position:"absolute",bottom:"16px",left:"50%",transform:"translateX(-50%)",background:"rgba(26,42,107,0.85)",color:"#c9a86c",fontSize:"0.6rem",letterSpacing:"0.15em",padding:"6px 16px",pointerEvents:"none",whiteSpace:"nowrap"}}>
        DRAG TO ROTATE &nbsp;·&nbsp; SCROLL TO ZOOM
      </div>
      <div style={{position:"absolute",top:"12px",left:"12px",color:"#1a2a6b",fontSize:"0.58rem",letterSpacing:"0.18em",fontWeight:700,background:"rgba(248,245,239,0.85)",padding:"4px 8px"}}>
        THE UNKNOWN &nbsp;·&nbsp; KAREL STOOP &nbsp;·&nbsp; 2026
      </div>
    </div>
  );
}

// ── VIDEO PLAYER ──
function VideoPlayer() {
  const videoRef = useRef(null);
  const [muted,setMuted] = useState(true);
  const [playing,setPlaying] = useState(false);
  useEffect(()=>{
    const v=videoRef.current; if(!v)return;
    v.play().then(()=>setPlaying(true)).catch(()=>setPlaying(false));
  },[]);
  const toggle=()=>{
    if(!videoRef.current)return;
    if(playing){videoRef.current.pause();setPlaying(false);}
    else{videoRef.current.play().catch(()=>{});setPlaying(true);}
  };
  const toggleMute=(e)=>{
    e.stopPropagation();
    if(!videoRef.current)return;
    videoRef.current.muted=!muted; setMuted(m=>!m);
  };
  return(
    <div style={{position:"relative",marginBottom:"0.5rem",background:"#0a0a0a",cursor:"pointer"}} onClick={toggle}>
      <video ref={videoRef} src={VIDEO_SRC} poster={POSTER_SRC} autoPlay muted playsInline loop style={{width:"100%",height:"240px",objectFit:"cover",display:"block"}}/>
      {!playing&&(
        <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",background:"rgba(0,0,0,0.35)"}}>
          <div style={{width:"52px",height:"52px",borderRadius:"50%",background:"rgba(201,168,108,0.9)",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <div style={{width:0,height:0,borderTop:"10px solid transparent",borderBottom:"10px solid transparent",borderLeft:"16px solid #1a2a6b",marginLeft:"4px"}}/>
          </div>
        </div>
      )}
      <div style={{position:"absolute",bottom:"0.6rem",left:"0.8rem",right:"0.8rem",display:"flex",justifyContent:"space-between",alignItems:"center",zIndex:3}}>
        <div style={{background:"rgba(26,42,107,0.85)",color:"#c9a86c",fontSize:"0.6rem",letterSpacing:"0.15em",padding:"0.2rem 0.6rem",textTransform:"uppercase"}}>Studio · Karel Stoop</div>
        <button onClick={toggleMute} style={{background:"rgba(0,0,0,0.6)",border:"1px solid rgba(201,168,108,0.4)",color:"#c9a86c",cursor:"pointer",fontSize:"0.65rem",padding:"0.2rem 0.5rem",fontFamily:"inherit"}}>
          {muted?"🔇 Sound off":"🔊 Sound on"}
        </button>
      </div>
    </div>
  );
}

// ── WATERMARKED IMAGE ──
function WatermarkedImage({src,alt,style,watermark}) {
  const canvasRef=useRef(null);
  const [ready,setReady]=useState(false);
  useEffect(()=>{
    setReady(false);
    if(!watermark.enabled){setReady(true);return;}
    const canvas=canvasRef.current; if(!canvas)return;
    const ctx=canvas.getContext("2d");
    const img=new Image();
    img.onload=()=>{
      canvas.width=img.width;canvas.height=img.height;
      ctx.drawImage(img,0,0);
      const fs=Math.max(18,img.width*0.022);
      ctx.font=`${watermark.style==="bold"?"600":"300"} ${fs}px Georgia,serif`;
      ctx.fillStyle=`rgba(255,255,255,${watermark.opacity/100})`;
      ctx.strokeStyle=`rgba(0,0,0,${(watermark.opacity/100)*0.5})`;
      ctx.lineWidth=fs*0.04;
      const text=`© ${watermark.year}  ${watermark.artist}`;
      const pad=fs*0.9;
      if(watermark.position==="diagonal"){
        ctx.save();ctx.translate(img.width/2,img.height/2);ctx.rotate(-Math.PI/8);
        ctx.textAlign="center";ctx.strokeText(text,0,0);ctx.fillText(text,0,0);ctx.restore();
      }else{
        ctx.textAlign=watermark.position.includes("right")?"right":"left";
        const x=watermark.position.includes("right")?img.width-pad:pad;
        const y=watermark.position.includes("top")?fs+pad:img.height-pad;
        ctx.strokeText(text,x,y);ctx.fillText(text,x,y);
        ctx.font=`600 ${fs*1.1}px Georgia,serif`;
        ctx.fillStyle=`rgba(201,168,108,${watermark.opacity/100})`;
        const gzX=watermark.position.includes("right")?img.width-pad-ctx.measureText(text).width-fs*1.4:pad;
        ctx.strokeText("GZ",gzX,y);ctx.fillText("GZ",gzX,y);
      }
      setReady(true);
    };
    img.src=src;
  },[src,watermark]);
  if(!watermark.enabled)return <img src={src} alt={alt} style={style} draggable={false}/>;
  return(
    <div style={{position:"relative",...style,overflow:"hidden"}}>
      <canvas ref={canvasRef} style={{width:"100%",height:"100%",objectFit:"cover",display:ready?"block":"none"}}/>
      {!ready&&<div style={{width:"100%",height:"100%",background:"#e8e0d0",display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{color:"#a09070",fontSize:"0.8rem"}}>Loading…</span></div>}
      <div style={{position:"absolute",inset:0,zIndex:2}} onContextMenu={e=>e.preventDefault()}/>
    </div>
  );
}

